update.if:
UPDATE STOCMUTM MUTM SET
      DEL_FLAG = '1'
    , MOD_USER_ID = #{ses.userId}
    , MOD_DATE = SYSDATE
 WHERE GATE_CD = #{ses.gateCd}
   AND TMPL_MENU_CD IN (SELECT TMPL_MENU_CD
                          FROM STOCMUTM
                         WHERE GATE_CD = MUTM.GATE_CD START WITH TMPL_MENU_CD = #{TMPL_MENU_CD}
                         CONNECT BY PRIOR TMPL_MENU_CD = HIGH_TMPL_MENU_CD
                           AND DEL_FLAG = '0')

select.if:
SELECT (MAX(SORT_SQ),0) + 1 AS SORT_SQ
  FROM STOCMUTM
 WHERE GATE_CD = #{ses.gateCd}
   AND HIGH_TMPL_MENU_CD = #{HIGH_TMPL_MENU_CD}

SELECT CAST((MAX(SORT_SQ),0) + 1 AS VARCHAR(10)) AS SORT_SQ
  FROM STOCMUTM
 WHERE GATE_CD = #{ses.gateCd}
   AND HIGH_TMPL_MENU_CD = #{HIGH_TMPL_MENU_CD}

		SELECT 'TM'(SF_LPAD(MAX(CONVERT(INT,SF_SUBSTR(TMPL_MENU_CD,3,6)))+1,6,'0'),'000001') AS CNT
          FROM STOCMUTM
         WHERE GATE_CD = #{ses.gateCd}

mapper.update:
UPDATE STOCMUTM SET
       SORT_SQ = SORT_SQ + 1
     , DEL_FLAG = '0'
     , MOD_DATE = SYSDATE
 WHERE GATE_CD = #{ses.gateCd}
   AND TMPL_MENU_GROUP_CD = #{TMPL_MENU_GROUP_CD}
   AND SORT_SQ >= #{SORT_SQ}
   AND DEL_FLAG = '0'

mapper.insert:
INSERT INTO STOCMUMS (
       GATE_CD
     , MENU_CD
     , REG_DATE
     , REG_USER_ID
     , MOD_DATE
     , MOD_USER_ID
     , MENU_GROUP_CD
     , MODULE_TYPE
     , TMPL_MENU_CD
     , DEL_FLAG
     , USE_FLAG
) VALUES(
       #{ses.gateCd}
     , (SELECT 'MC' (LPAD(MAX(TO_NUMBER(SF_SUBSTR(MENU_CD,3,6))+1),6,'0'),'000001') FROM STOCMUMS WHERE GATE_CD = #{ses.gateCd})
     , SYSDATE
     , #{ses.userId}
     , SYSDATE
     , #{ses.userId}
     , #{MENU_GROUP_CD}
     , #{MODULE_TYPE}
     , #{TMPL_MENU_CD}
     , '0'
     , '1'
)

